 1→/**
 2→ * PlatformProvider interface — decouples workflow orchestration from
 3→ * platform operations (issue fetching, PR creation, comments, labels).
 4→ *
 5→ * GitHub is the default implementation; alternatives can be added by
 6→ * implementing this interface without touching orchestration logic.
 7→ */
 8→
 9→/**
10→ * Normalized issue representation.
11→ */
12→export interface Issue {
13→  id: string;
14→  number: number;
15→  title: string;
16→  body: string;
17→  labels: string[];
18→  state: "open" | "closed";
19→}
20→
21→/**
22→ * Options for creating a pull request.
23→ */
24→export interface CreatePROptions {
25→  title: string;
26→  body: string;
27→  head: string;
28→  base: string;
29→}
30→
31→/**
32→ * Information about a created pull request.
33→ */
34→export interface PRInfo {
35→  number: number;
36→  url: string;
37→}
38→
39→/**
40→ * Status of a pull request.
41→ */
42→export interface PRStatus {
43→  state: "open" | "closed" | "merged";
44→}
45→
46→/**
47→ * A comment on an issue or pull request.
48→ */
49→export interface Comment {
50→  body: string;
51→  createdAt: string;
52→}
53→
54→/**
55→ * Interface that all platform backends must implement.
56→ */
57→export interface PlatformProvider {
58→  /** Platform name for logging/display */
59→  name: string;
60→
61→  /** Issue operations */
62→  fetchIssue(id: string): Promise<Issue>;
63→  postComment(issueId: string, body: string): Promise<void>;
64→  addLabel(issueId: string, label: string): Promise<void>;
65→  removeLabel(issueId: string, label: string): Promise<void>;
66→
67→  /** PR operations */
68→  createPR(opts: CreatePROptions): Promise<PRInfo>;
69→  getPRStatus(prId: string): Promise<PRStatus>;
70→  postPRComment(prId: string, body: string): Promise<void>;
71→
72→  /** Auth and health */
73→  checkAuth(): Promise<boolean>;
74→
75→  /** Phase marker operations */
76→  getIssueComments(issueId: string): Promise<Comment[]>;
77→}
