  1→/**
  2→ * GitHubProvider — PlatformProvider implementation wrapping the `gh` CLI.
  3→ *
  4→ * Owns all `gh` CLI calls for the orchestration layer. Skills continue
  5→ * to call `gh` directly for v1 (see Non-Goals in #368).
  6→ *
  7→ * Sync methods are provided for callers that are currently synchronous
  8→ * (phase-detection, pr-status, system, doctor, worktree-manager).
  9→ * Async interface methods delegate to the sync implementations.
 10→ */
 11→
 12→import { execSync, spawnSync } from "child_process";
 13→import type {
 14→  PlatformProvider,
 15→  Issue,
 16→  CreatePROptions,
 17→  PRInfo,
 18→  PRStatus,
 19→  Comment,
 20→} from "./platform-provider.js";
 21→
 22→/**
 23→ * PR merge status values (matches the casing returned by `gh pr view`).
 24→ */
 25→export type PRMergeStatus = "MERGED" | "CLOSED" | "OPEN" | null;
 26→
 27→/**
 28→ * Closed issue shape returned by `gh issue list --state closed`.
 29→ */
 30→export interface ClosedIssueRaw {
 31→  number: number;
 32→  title: string;
 33→  closedAt: string;
 34→  labels: { name: string }[];
 35→}
 36→
 37→/**
 38→ * Result of a raw `gh pr create` CLI call.
 39→ */
 40→export interface CreatePRCliResult {
 41→  stdout: string;
 42→  stderr: string;
 43→  exitCode: number | null;
 44→}
 45→
 46→/**
 47→ * Info returned for an issue in a batch query.
 48→ */
 49→export interface BatchIssueInfo {
 50→  number: number;
 51→  title: string;
 52→  state: "OPEN" | "CLOSED";
 53→}
 54→
 55→/**
 56→ * Info returned for a PR in a batch query.
 57→ */
 58→export interface BatchPRInfo {
 59→  number: number;
 60→  state: "OPEN" | "MERGED" | "CLOSED";
 61→}
 62→
 63→/**
 64→ * Result of a batch GitHub query.
 65→ */
 66→export interface BatchGitHubResult {
 67→  issues: Record<number, BatchIssueInfo>;
 68→  pullRequests: Record<number, BatchPRInfo>;
 69→  error?: string;
 70→}
 71→
 72→export class GitHubProvider implements PlatformProvider {
 73→  name = "github";
 74→
 75→  // ─── Sync helpers (for synchronous callers) ────────────────────────
 76→
 77→  /**
 78→   * Fetch issue comment bodies as a string array.
 79→   * Used by phase-detection.ts for phase marker parsing.
 80→   */
 81→  fetchIssueCommentBodiesSync(issueId: string): string[] {
 82→    try {
 83→      const result = spawnSync(
 84→        "gh",
 85→        [
 86→          "issue",
 87→          "view",
 88→          issueId,
 89→          "--json",
 90→          "comments",
 91→          "--jq",
 92→          "[.comments[].body]",
 93→        ],
 94→        { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], timeout: 15000 },
 95→      );
 96→      if (result.status !== 0 || !result.stdout) return [];
 97→      return JSON.parse(result.stdout) as string[];
 98→    } catch {
 99→      return [];
100→    }
101→  }
102→
103→  /**
104→   * Check if `gh` CLI is authenticated.
105→   * Used by system.ts and doctor.ts.
106→   */
107→  checkAuthSync(): boolean {
108→    try {
109→      execSync("gh auth status", { stdio: "ignore" });
110→      return true;
111→    } catch {
112→      return false;
113→    }
114→  }
115→
116→  /**
117→   * Get PR merge status by PR number.
118→   * Used by pr-status.ts and state-cleanup.ts.
119→   */
120→  getPRMergeStatusSync(prNumber: number): PRMergeStatus {
121→    try {
122→      const result = spawnSync(
123→        "gh",
124→        ["pr", "view", String(prNumber), "--json", "state", "-q", ".state"],
125→        { stdio: "pipe", timeout: 10000 },
126→      );
127→
128→      if (result.status === 0 && result.stdout) {
129→        const state = result.stdout.toString().trim().toUpperCase();
130→        if (state === "MERGED") return "MERGED";
131→        if (state === "CLOSED") return "CLOSED";
132→        if (state === "OPEN") return "OPEN";
133→      }
134→    } catch {
135→      // gh not available or error
136→    }
137→
138→    return null;
139→  }
140→
141→  /**
142→   * List recently closed issues.
143→   * Used by doctor.ts for closed-issue verification.
144→   */
145→  listClosedIssuesSync(limit: number = 100): ClosedIssueRaw[] {
146→    try {
147→      const result = spawnSync(
148→        "gh",
149→        [
150→          "issue",
151→          "list",
152→          "--state",
153→          "closed",
154→          "--json",
155→          "number,title,closedAt,labels",
156→          "--limit",
157→          String(limit),
158→        ],
159→        { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], timeout: 15000 },
160→      );
161→      if (result.status !== 0 || !result.stdout) return [];
162→      return JSON.parse(result.stdout) as ClosedIssueRaw[];
163→    } catch {
164→      return [];
165→    }
166→  }
167→
168→  /**
169→   * View a PR by branch name, returning number and URL.
170→   * Used by worktree-manager.ts to check for existing PRs.
171→   */
172→  viewPRByBranchSync(
173→    branch: string,
174→    cwd?: string,
175→  ): { number: number; url: string } | null {
176→    const result = spawnSync(
177→      "gh",
178→      ["pr", "view", branch, "--json", "number,url"],
179→      { stdio: "pipe", cwd, timeout: 15000 },
180→    );
181→
182→    if (result.status === 0 && result.stdout) {
183→      try {
184→        const info = JSON.parse(result.stdout.toString());
185→        if (info.number && info.url) {
186→          return { number: info.number, url: info.url };
187→        }
188→      } catch {
189→        // JSON parse failed
190→      }
191→    }
192→
193→    return null;
194→  }
195→
196→  /**
197→   * Get the head branch name for a PR by number.
198→   * Used by hooks/pre-tool.sh for pre-merge worktree cleanup.
199→   */
200→  getPRHeadBranchSync(prNumber: number): string | null {
201→    const result = spawnSync(
202→      "gh",
203→      [
204→        "pr",
205→        "view",
206→        String(prNumber),
207→        "--json",
208→        "headRefName",
209→        "--jq",
210→        ".headRefName",
211→      ],
212→      { stdio: "pipe", timeout: 10000 },
213→    );
214→
215→    if (result.status === 0 && result.stdout) {
216→      const branch = result.stdout.toString().trim();
217→      return branch || null;
218→    }
219→
220→    return null;
221→  }
222→
223→  /**
224→   * Create a PR via `gh pr create` CLI, returning raw result.
225→   * Used by worktree-manager.ts which needs access to stdout for URL extraction.
226→   */
227→  createPRCliSync(
228→    title: string,
229→    body: string,
230→    head: string,
231→    cwd?: string,
232→  ): CreatePRCliResult {
233→    const result = spawnSync(
234→      "gh",
235→      ["pr", "create", "--title", title, "--body", body, "--head", head],
236→      { stdio: "pipe", cwd, timeout: 30000 },
237→    );
238→
239→    return {
240→      stdout: result.stdout?.toString() ?? "",
241→      stderr: result.stderr?.toString() ?? "",
242→      exitCode: result.status,
243→    };
244→  }
245→
246→  /**
247→   * Batch fetch issue and PR status in a single GraphQL call.
248→   * Returns a map keyed by issue/PR number.
249→   */
250→  batchFetchIssueAndPRStatus(
251→    issueNumbers: number[],
252→    prNumbers: number[],
253→  ): BatchGitHubResult {
254→    if (issueNumbers.length === 0 && prNumbers.length === 0) {
255→      return { issues: {}, pullRequests: {}, error: undefined };
256→    }
257→
258→    try {
259→      // Build GraphQL query with aliases for each issue and PR
260→      const issueFields = issueNumbers
261→        .map((n) => `issue_${n}: issue(number: ${n}) { number title state }`)
262→        .join("\n    ");
263→      const prFields = prNumbers
264→        .map((n) => `pr_${n}: pullRequest(number: ${n}) { number state }`)
265→        .join("\n    ");
266→
267→      const query = `query {
268→  repository(owner: "{owner}", name: "{repo}") {
269→    ${issueFields}
270→    ${prFields}
271→  }
272→}`;
273→
274→      // Get repo owner/name
275→      const repoResult = spawnSync(
276→        "gh",
277→        ["repo", "view", "--json", "owner,name"],
278→        { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], timeout: 10000 },
279→      );
280→
281→      if (repoResult.status !== 0 || !repoResult.stdout) {
282→        return {
283→          issues: {},
284→          pullRequests: {},
285→          error: "Failed to determine repository",
286→        };
287→      }
288→
289→      const repo = JSON.parse(repoResult.stdout) as {
290→        owner: { login: string };
291→        name: string;
292→      };
293→      const filledQuery = query
294→        .replace("{owner}", repo.owner.login)
295→        .replace("{repo}", repo.name);
296→
297→      const result = spawnSync(
298→        "gh",
299→        ["api", "graphql", "-f", `query=${filledQuery}`],
300→        { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], timeout: 15000 },
301→      );
302→
303→      if (result.status !== 0 || !result.stdout) {
304→        const stderr = result.stderr?.trim() ?? "Unknown error";
305→        return { issues: {}, pullRequests: {}, error: stderr };
306→      }
307→
308→      const data = JSON.parse(result.stdout) as {
309→        data?: {
310→          repository?: Record<
311→            string,
312→            { number: number; title?: string; state: string }
313→          >;
314→        };
315→        errors?: Array<{ message: string }>;
316→      };
317→
318→      const issues: Record<number, BatchIssueInfo> = {};
319→      const pullRequests: Record<number, BatchPRInfo> = {};
320→
321→      const repoData = data.data?.repository ?? {};
322→
323→      for (const [key, value] of Object.entries(repoData)) {
324→        if (!value) continue;
325→        if (key.startsWith("issue_")) {
326→          issues[value.number] = {
327→            number: value.number,
328→            title: value.title ?? "",
329→            state: value.state as "OPEN" | "CLOSED",
330→          };
331→        } else if (key.startsWith("pr_")) {
332→          pullRequests[value.number] = {
333→            number: value.number,
334→            state: value.state as "OPEN" | "MERGED" | "CLOSED",
335→          };
336→        }
337→      }
338→
339→      return { issues, pullRequests, error: undefined };
340→    } catch (err) {
341→      return {
342→        issues: {},
343→        pullRequests: {},
344→        error: err instanceof Error ? err.message : String(err),
345→      };
346→    }
347→  }
348→
349→  // ─── Async interface methods (PlatformProvider) ────────────────────
350→
351→  async fetchIssue(id: string): Promise<Issue> {
352→    const result = spawnSync(
353→      "gh",
354→      ["issue", "view", id, "--json", "number,title,body,labels,state"],
355→      { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], timeout: 15000 },
356→    );
357→    if (result.status !== 0 || !result.stdout) {
358→      throw new Error(`Failed to fetch issue ${id}`);
359→    }
360→    const data = JSON.parse(result.stdout);
361→    return {
362→      id: String(data.number),
363→      number: data.number,
364→      title: data.title,
365→      body: data.body,
366→      labels: (data.labels ?? []).map((l: { name: string }) => l.name),
367→      state: data.state.toLowerCase() as "open" | "closed",
368→    };
369→  }
370→
371→  async postComment(issueId: string, body: string): Promise<void> {
372→    spawnSync("gh", ["issue", "comment", issueId, "--body", body], {
373→      stdio: "pipe",
374→      timeout: 15000,
375→    });
376→  }
377→
378→  async addLabel(issueId: string, label: string): Promise<void> {
379→    spawnSync("gh", ["issue", "edit", issueId, "--add-label", label], {
380→      stdio: "pipe",
381→      timeout: 15000,
382→    });
383→  }
384→
385→  async removeLabel(issueId: string, label: string): Promise<void> {
386→    spawnSync("gh", ["issue", "edit", issueId, "--remove-label", label], {
387→      stdio: "pipe",
388→      timeout: 15000,
389→    });
390→  }
391→
392→  async createPR(opts: CreatePROptions): Promise<PRInfo> {
393→    const result = this.createPRCliSync(opts.title, opts.body, opts.head);
394→
395→    if (result.exitCode !== 0) {
396→      const error = result.stderr.trim() || "Unknown error";
397→      throw new Error(`gh pr create failed: ${error}`);
398→    }
399→
400→    const urlMatch = result.stdout
401→      .trim()
402→      .match(/https:\/\/github\.com\/[^\s]+\/pull\/(\d+)/);
403→
404→    if (urlMatch) {
405→      return {
406→        number: parseInt(urlMatch[1], 10),
407→        url: urlMatch[0],
408→      };
409→    }
410→
411→    throw new Error(
412→      `PR created but could not extract URL from output: ${result.stdout.trim()}`,
413→    );
414→  }
415→
416→  async getPRStatus(prId: string): Promise<PRStatus> {
417→    const status = this.getPRMergeStatusSync(parseInt(prId, 10));
418→    if (status) {
419→      return { state: status.toLowerCase() as PRStatus["state"] };
420→    }
421→    throw new Error(`Could not determine PR status for ${prId}`);
422→  }
423→
424→  async postPRComment(prId: string, body: string): Promise<void> {
425→    spawnSync("gh", ["pr", "comment", prId, "--body", body], {
426→      stdio: "pipe",
427→      timeout: 15000,
428→    });
429→  }
430→
431→  async checkAuth(): Promise<boolean> {
432→    return this.checkAuthSync();
433→  }
434→
435→  async getIssueComments(issueId: string): Promise<Comment[]> {
436→    try {
437→      const result = spawnSync(
438→        "gh",
439→        [
440→          "issue",
441→          "view",
442→          issueId,
443→          "--json",
444→          "comments",
445→          "--jq",
446→          "[.comments[] | {body: .body, createdAt: .createdAt}]",
447→        ],
448→        { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], timeout: 15000 },
449→      );
450→      if (result.status !== 0 || !result.stdout) return [];
451→      const data = JSON.parse(result.stdout) as Array<{
452→        body: string;
453→        createdAt: string;
454→      }>;
455→      return data;
456→    } catch {
457→      return [];
458→    }
459→  }
460→}
