 1→/**
 2→ * AgentDriver interface — decouples workflow orchestration from agent execution.
 3→ *
 4→ * Claude Code is the default implementation; alternatives (Aider, Codex CLI,
 5→ * Continue.dev, Copilot SDK, Cursor API) can be added by implementing this
 6→ * interface without touching orchestration logic.
 7→ */
 8→
 9→/**
10→ * Configuration passed to an agent for phase execution.
11→ */
12→export interface AgentExecutionConfig {
13→  cwd: string;
14→  env: Record<string, string>;
15→  abortSignal?: AbortSignal;
16→  phaseTimeout: number;
17→  verbose: boolean;
18→  mcp: boolean;
19→  /** Resume a previous session (driver-specific; ignored if unsupported) */
20→  sessionId?: string;
21→  /** Callback for streaming output */
22→  onOutput?: (text: string) => void;
23→  /** Callback for stderr */
24→  onStderr?: (text: string) => void;
25→  /** Relevant files for the phase (used by file-oriented drivers like Aider) */
26→  files?: string[];
27→}
28→
29→/**
30→ * Result returned by an agent after executing a phase.
31→ */
32→export interface AgentPhaseResult {
33→  success: boolean;
34→  output: string;
35→  sessionId?: string;
36→  error?: string;
37→}
38→
39→/**
40→ * Interface that all agent backends must implement.
41→ *
42→ * The driver is responsible for executing a prompt and returning
43→ * a structured result. Parsing (QA verdicts, etc.) stays in
44→ * phase-executor.ts — the driver just captures text.
45→ */
46→export interface AgentDriver {
47→  /** Human-readable name for logging */
48→  name: string;
49→
50→  /** Execute a phase prompt and return structured result */
51→  executePhase(
52→    prompt: string,
53→    config: AgentExecutionConfig,
54→  ): Promise<AgentPhaseResult>;
55→
56→  /** Check if this driver is available/configured */
57→  isAvailable(): Promise<boolean>;
58→}
