  1→/**
  2→ * Label lifecycle management for CI-triggered workflows.
  3→ *
  4→ * Manages the sequant:solving → sequant:done / sequant:failed label
  5→ * transitions on GitHub issues during and after workflow execution.
  6→ */
  7→
  8→import { LIFECYCLE_LABELS, TRIGGER_LABELS } from "./types.js";
  9→
 10→/**
 11→ * All trigger labels that should be removed when a run starts.
 12→ */
 13→const TRIGGER_LABEL_SET: Set<string> = new Set(Object.values(TRIGGER_LABELS));
 14→
 15→/**
 16→ * Get labels to add when a workflow run starts.
 17→ */
 18→export function getStartLabels(): string[] {
 19→  return [LIFECYCLE_LABELS.SOLVING];
 20→}
 21→
 22→/**
 23→ * Get labels to remove when a workflow run starts.
 24→ * Removes the trigger label that initiated the run.
 25→ */
 26→export function getStartRemoveLabels(triggerLabel?: string): string[] {
 27→  const labels: string[] = [];
 28→
 29→  // Remove the trigger label
 30→  if (triggerLabel && TRIGGER_LABEL_SET.has(triggerLabel)) {
 31→    labels.push(triggerLabel);
 32→  }
 33→
 34→  // Remove any stale outcome labels from prior runs
 35→  labels.push(LIFECYCLE_LABELS.DONE, LIFECYCLE_LABELS.FAILED);
 36→
 37→  return labels;
 38→}
 39→
 40→/**
 41→ * Get labels to apply when a workflow completes successfully.
 42→ */
 43→export function getSuccessLabels(): { add: string[]; remove: string[] } {
 44→  return {
 45→    add: [LIFECYCLE_LABELS.DONE],
 46→    remove: [LIFECYCLE_LABELS.SOLVING],
 47→  };
 48→}
 49→
 50→/**
 51→ * Get labels to apply when a workflow fails.
 52→ */
 53→export function getFailureLabels(): { add: string[]; remove: string[] } {
 54→  return {
 55→    add: [LIFECYCLE_LABELS.FAILED],
 56→    remove: [LIFECYCLE_LABELS.SOLVING],
 57→  };
 58→}
 59→
 60→/**
 61→ * Generate gh CLI commands for label transitions.
 62→ * Useful for composite action shell steps.
 63→ */
 64→export function labelCommands(
 65→  issueNumber: number,
 66→  transition: "start" | "success" | "failure",
 67→  triggerLabel?: string,
 68→): string[] {
 69→  const commands: string[] = [];
 70→
 71→  switch (transition) {
 72→    case "start": {
 73→      for (const label of getStartLabels()) {
 74→        commands.push(`gh issue edit ${issueNumber} --add-label "${label}"`);
 75→      }
 76→      for (const label of getStartRemoveLabels(triggerLabel)) {
 77→        commands.push(
 78→          `gh issue edit ${issueNumber} --remove-label "${label}" 2>/dev/null || true`,
 79→        );
 80→      }
 81→      break;
 82→    }
 83→    case "success": {
 84→      const { add, remove } = getSuccessLabels();
 85→      for (const label of add) {
 86→        commands.push(`gh issue edit ${issueNumber} --add-label "${label}"`);
 87→      }
 88→      for (const label of remove) {
 89→        commands.push(
 90→          `gh issue edit ${issueNumber} --remove-label "${label}" 2>/dev/null || true`,
 91→        );
 92→      }
 93→      break;
 94→    }
 95→    case "failure": {
 96→      const { add, remove } = getFailureLabels();
 97→      for (const label of add) {
 98→        commands.push(`gh issue edit ${issueNumber} --add-label "${label}"`);
 99→      }
100→      for (const label of remove) {
101→        commands.push(
102→          `gh issue edit ${issueNumber} --remove-label "${label}" 2>/dev/null || true`,
103→        );
104→      }
105→      break;
106→    }
107→  }
108→
109→  return commands;
110→}
