192→/**
193→ * Fetch issue title from GitHub via gh CLI.
194→ * Returns null if gh is not available or the issue doesn't exist.
195→ */
196→function fetchIssueTitle(issueNumber: number): string | null {
197→  const result = spawnSync(
198→    "gh",
199→    ["issue", "view", String(issueNumber), "--json", "title", "--jq", ".title"],
200→    { stdio: "pipe", encoding: "utf-8", timeout: 10_000 },
201→  );
202→  if (result.status !== 0 || !result.stdout?.trim()) {
203→    return null;
204→  }
205→  return result.stdout.trim();
206→}
