  5→ * @example
  6→ * ```typescript
  7→ * import { checkPRMergeStatus, isBranchMergedIntoMain, isIssueMergedIntoMain } from './pr-status';
  8→ *
  9→ * // Check PR status via GitHub CLI
 10→ * const status = checkPRMergeStatus(123);
 11→ * if (status === 'MERGED') {
 12→ *   console.log('PR is merged');
 13→ * }
 14→ *
 15→ * // Check if branch is merged into main
 16→ * const isMerged = isBranchMergedIntoMain('feature/123-some-feature');
 17→ * ```
 18→ */
 19→
 20→import { spawnSync } from "child_process";
 21→import { GitHubProvider } from "./platforms/github.js";
 22→import type { PRMergeStatus } from "./platforms/github.js";
 23→
 24→export type { PRMergeStatus };
 25→
 26→/**
 27→ * Check the merge status of a PR using the gh CLI
 28→ *
 29→ * @param prNumber - The PR number to check
 30→ * @returns "MERGED" | "CLOSED" | "OPEN" | null (null if PR not found or gh unavailable)
 31→ */
 32→export function checkPRMergeStatus(prNumber: number): PRMergeStatus {
 33→  const github = new GitHubProvider();
 34→  return github.getPRMergeStatusSync(prNumber);
 35→}
