 37→/**
 38→ * Check if a branch has been merged into a base branch using git
 39→ *
 40→ * @param branchName - The branch name to check (e.g., "feature/33-some-title")
 41→ * @param baseBranch - The base branch to check against (default: "main")
 42→ * @returns true if the branch is merged into the base branch, false otherwise
 43→ */
 44→export function isBranchMergedIntoMain(
 45→  branchName: string,
 46→  baseBranch: string = "main",
 47→): boolean {
 48→  try {
 49→    // Get branches merged into the base branch
 50→    const result = spawnSync("git", ["branch", "--merged", baseBranch], {
 51→      stdio: "pipe",
 52→      timeout: 10000,
 53→    });
 54→
 55→    if (result.status === 0 && result.stdout) {
 56→      const mergedBranches = result.stdout.toString();
 57→      // Check if our branch is in the list (handle both local and remote refs)
 58→      return (
 59→        mergedBranches.includes(branchName) ||
 60→        mergedBranches.includes(`remotes/origin/${branchName}`)
 61→      );
 62→    }
 63→  } catch {
 64→    // git command failed - return false
 65→  }
 66→
 67→  return false;
 68→}
 69→
 70→/**
 71→ * Check if a feature branch for an issue is merged into a base branch
 72→ *
 73→ * Tries multiple detection methods:
 74→ * 1. Check if branch exists and is merged via `git branch --merged <baseBranch>`
 75→ * 2. Check for merge commits mentioning the issue
 76→ *
 77→ * @param issueNumber - The issue number to check
 78→ * @param baseBranch - The base branch to check against (default: "main")
 79→ * @returns true if the issue's work is merged into the base branch
 80→ */
 81→export function isIssueMergedIntoMain(
 82→  issueNumber: number,
 83→  baseBranch: string = "main",
 84→): boolean {
 85→  try {
 86→    // Method 1: Check if any feature branch for this issue is merged
 87→    const listResult = spawnSync("git", ["branch", "-a"], {
 88→      stdio: "pipe",
 89→      timeout: 10000,
 90→    });
 91→
 92→    if (listResult.status === 0 && listResult.stdout) {
 93→      const branches = listResult.stdout.toString();
 94→      // Find branches matching feature/<issue>-*
 95→      const branchPattern = new RegExp(`feature/${issueNumber}-[^\\s]+`, "g");
 96→      const matchedBranches = branches.match(branchPattern);
 97→
 98→      if (matchedBranches) {
 99→        for (const branch of matchedBranches) {
100→          const cleanBranch = branch.replace(/^\*?\s*/, "").trim();
101→          if (isBranchMergedIntoMain(cleanBranch, baseBranch)) {
102→            return true;
103→          }
104→        }
105→      }
106→    }
107→
108→    // Method 2: Check for merge commits mentioning the issue
109→    // Use specific merge patterns to avoid false positives from
110→    // unrelated commits that merely reference the issue number
111→    const logResult = spawnSync(
112→      "git",
113→      [
114→        "log",
115→        baseBranch,
116→        "--oneline",
117→        "-20",
118→        "--grep",
119→        `Merge #${issueNumber}`,
120→        "--grep",
121→        `Merge.*#${issueNumber}`,
122→        "--grep",
123→        `(#${issueNumber})`,
124→      ],
125→      {
126→        stdio: "pipe",
127→        timeout: 10000,
128→      },
129→    );
130→
131→    if (logResult.status === 0 && logResult.stdout) {
132→      const commits = logResult.stdout.toString().trim();
133→      if (commits.length > 0) {
134→        return true;
135→      }
136→    }
137→  } catch {
138→    // git command failed - return false
139→  }
140→
141→  return false;
142→}
