 74→function parseIssueNumberFromBranch(branch: string): number | null {
 75→  // Pattern: feature/123-description or feature/123
 76→  const featureMatch = branch.match(/^feature\/(\d+)(?:-|$)/);
 77→  if (featureMatch) {
 78→    return parseInt(featureMatch[1], 10);
 79→  }
