 81→  // Pattern: issue-123
 82→  const issueMatch = branch.match(/^issue-(\d+)$/);
 83→  if (issueMatch) {
 84→    return parseInt(issueMatch[1], 10);
 85→  }
 86→
 87→  // Pattern: 123-description (bare number prefix)
 88→  const bareMatch = branch.match(/^(\d+)-/);
 89→  if (bareMatch) {
 90→    return parseInt(bareMatch[1], 10);
 91→  }
 92→
 93→  return null;
 94→}
