148→        worktrees.push(current as WorktreeInfo);
149→      }
150→      current = { path: line.substring(9) };
151→    } else if (line.startsWith("HEAD ")) {
152→      current.head = line.substring(5);
153→    } else if (line.startsWith("branch refs/heads/")) {
154→      current.branch = line.substring(18);
155→    } else if (line === "" && current.path) {
156→      // End of entry
157→      worktrees.push(current as WorktreeInfo);
158→      current = {};
159→    }
160→  }
161→
162→  // Don't forget the last entry
163→  if (current.path && current.branch) {
164→    worktrees.push(current as WorktreeInfo);
165→  }
166→
167→  return worktrees;
168→}
169→
170→/**
171→ * Infer the current phase for an issue by checking logs
172→ */
173→function inferPhaseFromLogs(issueNumber: number): Phase | undefined {
174→  const logPath = LOG_PATHS.project;
175→
176→  if (!fs.existsSync(logPath)) {
177→    return undefined;
178→  }
179→
180→  try {
181→    const files = fs.readdirSync(logPath).filter((f) => f.endsWith(".json"));
182→
183→    // Sort by timestamp (newest first)
184→    files.sort().reverse();
185→
186→    for (const file of files) {
187→      try {
188→        const content = fs.readFileSync(path.join(logPath, file), "utf-8");
189→        const logData = JSON.parse(content);
190→        const log = RunLogSchema.safeParse(logData);
191→
192→        if (!log.success) continue;
193→
194→        // Find this issue in the log
195→        const issueLog = log.data.issues.find(
196→          (i) => i.issueNumber === issueNumber,
197→        );
198→        if (issueLog && issueLog.phases.length > 0) {
199→          // Return the last executed phase
200→          const lastPhase = issueLog.phases[issueLog.phases.length - 1];
201→          return lastPhase.phase as Phase;
202→        }
203→      } catch {
204→        continue;
205→      }
206→    }
207→  } catch {
208→    return undefined;
209→  }
210→
211→  return undefined;
212→}
213→
214→/**
215→ * Discover worktrees that are not yet tracked in state
216→ *
217→ * Scans all git worktrees, identifies those with issue-related branch names,
218→ * and returns information about worktrees not yet in the state file.
219→ */
220→export async function discoverUntrackedWorktrees(
221→  options: DiscoverOptions = {},
222→): Promise<DiscoverResult> {
223→  try {
224→    const worktrees = getWorktreeDetails();
225→    const discovered: DiscoveredWorktree[] = [];
226→    const skipped: SkippedWorktree[] = [];
227→    let alreadyTracked = 0;
228→
229→    // Get existing state
230→    const manager = new StateManager({
231→      statePath: options.statePath,
232→      verbose: options.verbose,
233→    });
234→    const state = await manager.getState();
235→    const trackedIssues = new Set(
236→      Object.keys(state.issues).map((n) => parseInt(n, 10)),
237→    );
238→
239→    for (const worktree of worktrees) {
240→      // Skip if no branch (detached HEAD)
241→      if (!worktree.branch) {
242→        skipped.push({
243→          path: worktree.path,
244→          reason: "detached HEAD (no branch)",
245→        });
246→        continue;
247→      }
248→
249→      // Skip main/master branches
250→      if (worktree.branch === "main" || worktree.branch === "master") {
251→        skipped.push({
252→          path: worktree.path,
253→          reason: "main/master branch (not a feature worktree)",
254→        });
255→        continue;
256→      }
257→
258→      // Try to parse issue number from branch
259→      const issueNumber = parseIssueNumberFromBranch(worktree.branch);
260→      if (issueNumber === null) {
261→        skipped.push({
262→          path: worktree.path,
263→          reason: `branch name doesn't match issue pattern: ${worktree.branch}`,
264→        });
265→        continue;
266→      }
267→
268→      // Check if already tracked
269→      if (trackedIssues.has(issueNumber)) {
270→        alreadyTracked++;
271→        if (options.verbose) {
272→          console.log(
273→            `  Already tracked: #${issueNumber} (${worktree.branch})`,
274→          );
275→        }
276→        continue;
277→      }
278→
279→      // Fetch title from GitHub
280→      if (options.verbose) {
281→        console.log(`  Fetching title for #${issueNumber}...`);
282→      }
283→      const title = fetchIssueTitle(issueNumber);
284→
285→      // Try to infer phase from logs
286→      const inferredPhase = inferPhaseFromLogs(issueNumber);
287→
288→      discovered.push({
289→        issueNumber,
290→        title,
291→        worktreePath: worktree.path,
292→        branch: worktree.branch,
293→        inferredPhase,
294→      });
295→
296→      if (options.verbose) {
297→        console.log(
298→          `  Discovered: #${issueNumber} - ${title}${inferredPhase ? ` (phase: ${inferredPhase})` : ""}`,
299→        );
300→      }
301→    }
302→
303→    return {
304→      success: true,
305→      worktreesScanned: worktrees.length,
306→      alreadyTracked,
307→      discovered,
308→      skipped,
309→    };
310→  } catch (error) {
311→    return {
312→      success: false,
313→      worktreesScanned: 0,
314→      alreadyTracked: 0,
315→      discovered: [],
316→      skipped: [],
317→      error: String(error),
318→    };
319→  }
320→}
