 25→/**
 26→ * Regex pattern for valid semantic version strings
 27→ * Matches: v1.2.3, 1.2.3, v1.2.3-beta.1, v1.2.3-rc1, etc.
 28→ */
 29→const VERSION_PATTERN = /^v?\d+\.\d+\.\d+(-[\w.]+)?$/;
 30→
 31→/**
 32→ * Validate a version string to prevent command injection
 33→ * @throws Error if version format is invalid
 34→ */
 35→export function validateVersion(version: string): void {
 36→  if (!VERSION_PATTERN.test(version)) {
 37→    throw new Error(
 38→      `Invalid version format: "${version}". Expected semver format (e.g., v1.2.3 or 1.2.3-beta.1)`,
 39→    );
 40→  }
 41→}
