 43→/**
 44→ * Execute a command safely using spawn with argument arrays
 45→ * This prevents command injection by not using shell interpolation
 46→ */
 47→async function execCommand(
 48→  command: string,
 49→  args: string[],
 50→): Promise<{ stdout: string; stderr: string }> {
 51→  return new Promise((resolve, reject) => {
 52→    const proc = spawn(command, args, { stdio: ["pipe", "pipe", "pipe"] });
 53→    let stdout = "";
 54→    let stderr = "";
 55→
 56→    proc.stdout.on("data", (data) => {
 57→      stdout += data.toString();
 58→    });
 59→
 60→    proc.stderr.on("data", (data) => {
 61→      stderr += data.toString();
 62→    });
 63→
 64→    proc.on("close", (code) => {
 65→      if (code === 0) {
 66→        resolve({ stdout, stderr });
 67→      } else {
 68→        reject(new Error(`Command failed with exit code ${code}: ${stderr}`));
 69→      }
 70→    });
 71→
 72→    proc.on("error", (err) => {
 73→      reject(err);
 74→    });
 75→  });
 76→}
