269→/**
270→ * Run a single version assessment
271→ */
272→export async function assessVersion(
273→  version: string,
274→  options: AssessmentOptions = {},
275→): Promise<UpstreamAssessment | null> {
276→  const { dryRun = false, force = false } = options;
277→
278→  // Check if already assessed
279→  if (!force && (await isAlreadyAssessed(version))) {
280→    console.log(`Already assessed: ${version}. Use --force to re-assess.`);
281→    return null;
282→  }
283→
284→  // Fetch release
285→  const release = await fetchRelease(version);
286→  if (!release) {
287→    console.error(`Failed to fetch release: ${version}`);
288→    return null;
289→  }
290→
291→  // Load baseline
292→  const baseline = await loadBaseline();
293→
294→  // Analyze
295→  const findings = analyzeRelease(release.body, baseline);
296→  const actionableFindings = getActionableFindings(findings);
297→
298→  // Create assessment object
299→  const assessment: UpstreamAssessment = {
300→    version: release.tagName,
301→    releaseDate: release.publishedAt.split("T")[0],
302→    assessmentDate: new Date().toISOString().split("T")[0],
303→    previousVersion: baseline.lastAssessedVersion,
304→    findings,
305→    issuesCreated: [],
306→    summary: calculateSummary(findings),
307→    dryRun,
308→  };
309→
310→  // Create assessment issue first (to get issue number for linking)
311→  const assessmentBody = generateAssessmentReport(assessment);
312→  const assessmentIssueNumber = await createAssessmentIssue(
313→    `Upstream: Claude Code ${release.tagName} Assessment`,
314→    assessmentBody,
315→    dryRun,
316→  );
317→
318→  // Create issues for actionable findings (excluding opportunities —
319→  // opportunities are listed in the assessment but don't get individual issues)
320→  const issueWorthy = actionableFindings.filter(
321→    (f) => f.category !== "opportunity",
322→  );
323→  for (let i = 0; i < issueWorthy.length; i++) {
324→    const updatedFinding = await createOrLinkFinding(
325→      issueWorthy[i],
326→      release.tagName,
327→      assessmentIssueNumber,
328→      dryRun,
329→    );
330→
331→    // Update in original findings array
332→    const originalIndex = findings.findIndex(
333→      (f) => f.description === updatedFinding.description,
334→    );
335→    if (originalIndex >= 0) {
336→      findings[originalIndex] = updatedFinding;
337→    }
338→
339→    if (updatedFinding.issueNumber) {
340→      assessment.issuesCreated.push(updatedFinding.issueNumber);
341→    }
342→  }
343→
344→  // Save local report
345→  await saveLocalReport(assessment);
346→
347→  // Update baseline
348→  if (!dryRun) {
349→    await updateBaseline(release.tagName);
350→  }
351→
352→  return assessment;
353→}
