370→/**
371→ * Run batched assessment for multiple versions
372→ */
373→export async function assessSince(
374→  sinceVersion: string,
375→  options: AssessmentOptions = {},
376→): Promise<BatchedAssessment | null> {
377→  const { dryRun = false } = options;
378→
379→  const versions = await getReleasesSince(sinceVersion);
380→  if (versions.length === 0) {
381→    console.log(`No new versions since ${sinceVersion}`);
382→    return null;
383→  }
384→
385→  console.log(
386→    `Found ${versions.length} versions to assess: ${versions.join(", ")}`,
387→  );
388→
389→  const assessments: UpstreamAssessment[] = [];
390→
391→  for (const version of versions) {
392→    const assessment = await assessVersion(version, {
393→      ...options,
394→      force: true,
395→    });
396→    if (assessment) {
397→      assessments.push(assessment);
398→    }
399→  }
400→
401→  if (assessments.length === 0) {
402→    return null;
403→  }
404→
405→  const batched: BatchedAssessment = {
406→    versions,
407→    assessments,
408→    sinceVersion,
409→    toVersion: versions[versions.length - 1],
410→  };
411→
412→  // Create summary issue
413→  if (!dryRun) {
414→    const summaryBody = generateBatchedSummaryReport(batched);
415→    const summaryIssue = await createAssessmentIssue(
416→      `Upstream: Claude Code Assessment (${sinceVersion} → ${batched.toVersion})`,
417→      summaryBody,
418→      dryRun,
419→    );
420→    batched.summaryIssueNumber = summaryIssue;
421→  }
422→
423→  return batched;
424→}
