429→export async function runUpstream(
430→  options: AssessmentOptions = {},
431→): Promise<UpstreamAssessment | BatchedAssessment | null> {
432→  const { version, since } = options;
433→
434→  if (since) {
435→    return assessSince(since, options);
436→  }
437→
438→  if (version) {
439→    return assessVersion(version, options);
440→  }
441→
442→  return assessLatest(options);
443→}
