 1→/**
 2→ * Agent driver registry.
 3→ *
 4→ * Simple map-based registry — not a plugin system.
 5→ * New drivers are registered by adding entries to DRIVERS.
 6→ */
 7→
 8→import type { AgentDriver } from "./agent-driver.js";
 9→import type { AiderSettings } from "../../settings.js";
10→import { ClaudeCodeDriver } from "./claude-code.js";
11→import { AiderDriver } from "./aider.js";
12→
13→export type {
14→  AgentDriver,
15→  AgentExecutionConfig,
16→  AgentPhaseResult,
17→} from "./agent-driver.js";
18→
19→const DRIVERS: Record<string, (opts?: DriverOptions) => AgentDriver> = {
20→  "claude-code": () => new ClaudeCodeDriver(),
21→  aider: (opts) => new AiderDriver(opts?.aiderSettings),
22→};
23→
24→export interface DriverOptions {
25→  aiderSettings?: AiderSettings;
26→}
27→
28→/**
29→ * Get an agent driver by name.
30→ *
31→ * @param name - Driver name (default: "claude-code")
32→ * @param options - Optional driver-specific settings
33→ * @throws Error if driver name is unknown
34→ */
35→export function getDriver(
36→  name: string = "claude-code",
37→  options?: DriverOptions,
38→): AgentDriver {
39→  const factory = DRIVERS[name];
40→  if (!factory) {
41→    const available = Object.keys(DRIVERS).join(", ");
42→    throw new Error(
43→      `Unknown agent driver "${name}". Available drivers: ${available}`,
44→    );
45→  }
46→  return factory(options);
47→}
