 60→ */
 61→export function getInstallHint(pkg: string): string {
 62→  const platform = process.platform;
 63→
 64→  const hints: Record<string, Record<string, string>> = {
 65→    jq: {
 66→      darwin: "brew install jq",
 67→      linux: "apt install jq  # or: yum install jq",
 68→      win32: "choco install jq  # or: scoop install jq",
 69→    },
 70→    gh: {
 71→      darwin: "brew install gh",
 72→      linux: "apt install gh  # see: https://cli.github.com",
 73→      win32: "choco install gh  # or: winget install GitHub.cli",
 74→    },
 75→    claude: {
 76→      darwin: "npm install -g @anthropic-ai/claude-code",
 77→      linux: "npm install -g @anthropic-ai/claude-code",
 78→      win32: "npm install -g @anthropic-ai/claude-code",
 79→    },
 80→  };
 81→
 82→  const pkgHints = hints[pkg];
 83→  if (!pkgHints) {
 84→    return `Install ${pkg}`;
 85→  }
 86→
 87→  return pkgHints[platform] || pkgHints["linux"] || `Install ${pkg}`;
 88→}
