126→/**
127→ * Get the path to Claude Desktop config file
128→ */
129→export function getClaudeConfigPath(): string {
130→  const platform = process.platform;
131→  const home = process.env.HOME || process.env.USERPROFILE || "";
132→
133→  if (platform === "darwin") {
134→    return `${home}/Library/Application Support/Claude/claude_desktop_config.json`;
135→  } else if (platform === "win32") {
136→    return `${process.env.APPDATA}\\Claude\\claude_desktop_config.json`;
137→  } else {
138→    // Linux
139→    return `${home}/.config/claude/claude_desktop_config.json`;
140→  }
141→}
