145→ */
146→export function getConfiguredMcpServers(): string[] {
147→  const configPath = getClaudeConfigPath();
148→
149→  try {
150→    const content = fs.readFileSync(configPath, "utf8");
151→    const config = JSON.parse(content);
152→    const servers = config.mcpServers || {};
153→    return Object.keys(servers);
