172→ *
173→ * Returns the complete mcpServers object suitable for passing to the
174→ * Claude Agent SDK query() options. Returns undefined if config doesn't
175→ * exist or is invalid (graceful degradation for AC-3).
176→ *
177→ * @returns MCP server configurations or undefined
178→ */
179→export function getMcpServersConfig():
180→  | Record<string, McpServerConfig>
181→  | undefined {
182→  const configPath = getClaudeConfigPath();
183→
184→  try {
185→    const content = fs.readFileSync(configPath, "utf8");
186→    const config = JSON.parse(content);
187→    const servers = config.mcpServers;
188→
189→    // Return undefined if no mcpServers section exists
190→    if (!servers || typeof servers !== "object") {
191→      return undefined;
192→    }
193→
194→    return servers as Record<string, McpServerConfig>;
195→  } catch {
196→    // Config file doesn't exist or is invalid - graceful degradation
197→    return undefined;
198→  }
199→}
