201→/**
202→ * Check which optional MCP servers are configured
203→ * Returns an object with server names as keys and configured status as values
204→ */
205→export function checkOptionalMcpServers(): Record<string, boolean> {
206→  const configuredServers = getConfiguredMcpServers();
207→  const result: Record<string, boolean> = {};
208→
209→  for (const server of OPTIONAL_MCP_SERVERS) {
210→    // Check for various naming conventions
211→    const found = configuredServers.some(
212→      (configured) =>
213→        configured.toLowerCase().includes(server.name.toLowerCase()) ||
214→        server.name.toLowerCase().includes(configured.toLowerCase()),
215→    );
216→    result[server.name] = found;
217→  }
218→
219→  return result;
